







































































































import Vue from "vue";
import panelBlock from "./panel-block.vue";
import {
  validateSize,
  cssSizesWidth,
} from 'nano-grid/modules/columns-manager';
import {
  gColorsDB,
} from '../db/colors';

export default Vue.extend({
  components: {panelBlock},
  props: {
    name: {
      type: String,
      default: "",
    },
    index: undefined,
  },
  data: () => ({
    cssSizes: cssSizesWidth,
    gridType: [
      'Percent',
      'Fixed',
      'Twelve Grid',
      'Column Based'
    ],
    styles: [
      'prefix',
      'column',
      'suffix',
    ],
    gColorsDB: gColorsDB,
    selection: {columns: []},
  }),
  mounted() {
    this.selection = this.$store.getters.getSelection;
  },
  computed: {
    fixedValues():Array<string> {
      let result = [];
      for(let c = 5; c <= 60; c++ ){
        result.push(`${c * 5}`);
      }
      return result;
    },
    fixedSubstractionValues():Array<string> {
      let result = [];
      for(let c = 1; c <= 120; c++ ){
        result.push(`${c * 5}`);
      }
      return result;
    },
    percentsValues():Array<string> {
      let result = [];
      for(let c = 1; c*5 <= 100; c++ ){
        result.push(`${c * 5}%`);
      }
      return result;
    },
    twelveValues():Array<string> {
      let result = [];
      for(let c = 1; c <= 12; c++ ){
        result.push(`${c}/12`);
      }
      return result;
    },
    columnsValues():Array<string> {
      let result = [];
      for(let c = 1; c <= 20; c++ ){
        result.push(`1/${c}`);
      }
      return result;
    },
    finalValue():string {
      let result = "";
      if(this.selection.columns[this.index].size){
        result += this.selection.columns[this.index].size;
        if(this.selection.columns[this.index].subtraction > 0){
          result += `-${this.selection.columns[this.index].subtraction}`;
        }
      }
      return validateSize(result);
    },
  },
  methods: {
    removeBlock() {
      this.$store.commit("removeColumn", this.index);
      this.selection = this.$store.getters.getSelection;
    }
  }
});
